def make_q(id, game, lang, diff, code, options, correct, explanation):
    return f"""  {{ id: '{id}', game: '{game}', language: '{lang}', difficulty: '{diff}',
    code: '{code}',
    options: {json.dumps(options)},
    correctIndex: {correct}, explanation: '{explanation}' }},"""

