for i, (code, options, correct, explanation) in enumerate(q_data, start=1):
    questions.append(make_q(f'cc-ht-h{i}', 'code-completion', 'html', 'hard', code, options, correct, explanation))

questions = questions[:100]
print(f"Generated {len(questions)} HTML code-completion hard questions")

# Now replace in gameQuestions.ts
with open('/home/z/my-project/src/lib/gameQuestions.ts', 'r') as f:
    content = f.read()

new_body = '\n'.join(questions)
old_match = re.search(r'const Q_cc_ht_h: GameQuestion\[\]\s*=\s*\[.*?\];', content, re.DOTALL)
if old_match:
    content = content[:old_match.start()] + f'const Q_cc_ht_h: GameQuestion[] = [\n{new_body}\n];' + content[old_match.end():]
    with open('/home/z/my-project/src/lib/gameQuestions.ts', 'w') as f:
        f.write(content)
    print(f"Replaced! File: {len(content)} chars")
    verify = re.findall(r"game: 'code-completion', language: 'html', difficulty: 'hard'", content)
    print(f"Verified: {len(verify)} cc-ht-h questions in final file")
